import { useGameStore } from '../store/useGameStore';
import { useMovement } from '../hooks/useMovement';
import Character from './Character';
import { motion } from 'framer-motion';
import { TILE_SIZE, MAP_WIDTH_TILES, MAP_HEIGHT_TILES, WALLS, DOORS } from '../utils/mapGeometry';

export default function GameCanvas() {
  const { myPosition } = useGameStore();
  useMovement();

  return (
    <div className="w-full h-full flex items-center justify-center bg-black overflow-hidden relative">
      <motion.div 
        className="absolute"
        animate={{
          x: `calc(50vw - ${(myPosition.x + 0.5) * TILE_SIZE}px)`,
          y: `calc(50vh - ${(myPosition.y + 0.5) * TILE_SIZE}px)`
        }}
        transition={{ type: 'tween', duration: 0 }}
        style={{
          width: MAP_WIDTH_TILES * TILE_SIZE,
          height: MAP_HEIGHT_TILES * TILE_SIZE,
        }}
      >
        {/* FLOOR */}
        <div className="absolute inset-0 map-floor" />

        {/* MAP GEOMETRY */}
        {WALLS.map((wall, i) => (
          <div 
            key={`wall-${i}`}
            className="absolute map-wall z-10"
            style={{
              left: wall.x * TILE_SIZE,
              top: wall.y * TILE_SIZE,
              width: wall.w * TILE_SIZE,
              height: wall.h * TILE_SIZE
            }}
          />
        ))}

        {/* DOORS */}
        {Object.values(DOORS).map((door, i) => (
          <div
            key={`door-${i}`}
            className="absolute bg-slate-800/80 border-2 border-slate-600 z-10 flex items-center justify-center pixel-shadow"
            style={{
              left: door.x * TILE_SIZE,
              top: door.y * TILE_SIZE,
              width: door.w * TILE_SIZE,
              height: door.h * TILE_SIZE
            }}
          >
            <span className="text-[6px] text-white rotate-90 opacity-50 font-pixel">DOOR</span>
          </div>
        ))}

        {/* Floor Text Overlays */}
        {Object.values(DOORS).map((door, i) => {
          // Position the name inside the cabin
          const isLeft = door.x < 32;
          const isTop = door.y < 18;
          return (
            <div 
              key={`label-${i}`}
              className="absolute text-white/30 font-pixel drop-shadow-md pixel-shadow pointer-events-none text-2xl"
              style={{
                left: (isLeft ? 8 : 46) * TILE_SIZE,
                top: (isTop ? 6 : 26) * TILE_SIZE,
              }}
            >
              {door.ownerName}'s Cabin
            </div>
          );
        })}

        <div className="absolute text-white/30 font-pixel drop-shadow-md pixel-shadow pointer-events-none text-xl"
             style={{ left: 30 * TILE_SIZE, top: 18 * TILE_SIZE }}>
          HALLWAY
        </div>

        {/* CHARACTER */}
        {myPosition && (
          <Character 
            x={myPosition.x} 
            y={myPosition.y} 
            name={useGameStore.getState().currentUser?.name || "Red"} 
            color={useGameStore.getState().currentUser?.color || "#d7263d"} 
            direction={myPosition.direction} 
          />
        )}
      </motion.div>
    </div>
  );
}

import { useEffect } from 'react';
import { useGameStore } from '../store/useGameStore';
import { MAP_WIDTH_TILES, MAP_HEIGHT_TILES, WALLS, DOORS } from '../utils/mapGeometry';
import { notificationsChannel } from '../lib/supabase';

const MOVES = {
  KeyW: { dx: 0, dy: -1 },
  ArrowUp: { dx: 0, dy: -1 },
  KeyS: { dx: 0, dy: 1 },
  ArrowDown: { dx: 0, dy: 1 },
  KeyA: { dx: -1, dy: 0 },
  ArrowLeft: { dx: -1, dy: 0 },
  KeyD: { dx: 1, dy: 0 },
  ArrowRight: { dx: 1, dy: 0 },
};

const TILE_SPEED = 10; // tiles per second
const PLAYER_SIZE = 0.8; // bounding box relative to tile size
const OFFSET = 0.1;

const isColliding = (px, py, pw, ph, rect) => {
  return px < rect.x + rect.w &&
         px + pw > rect.x &&
         py < rect.y + rect.h &&
         py + ph > rect.y;
};

let lastKnockTime = 0;
const triggerKnock = (door) => {
  const now = performance.now();
  if (now - lastKnockTime > 2000) {
    lastKnockTime = now;

    // Dispatch in-game notification event locally
    window.dispatchEvent(new CustomEvent('in-game-notification', {
      detail: { message: `🗯️ *BAM BAM BAM* You aggressively knocked on ${door.ownerName}'s door! (Notification Sent)` }
    }));

    // Broadcast knock globally!
    const knockerName = useGameStore.getState().currentUser?.name || 'Someone';
    notificationsChannel.send({
      type: 'broadcast',
      event: 'knock',
      payload: { knockerName, ownerId: door.ownerId }
    });

    try {
      const ctx = new (window.AudioContext || window.webkitAudioContext)();
      const playKnock = (delay) => {
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.connect(gain);
        gain.connect(ctx.destination);
        osc.type = 'square';
        osc.frequency.setValueAtTime(150, ctx.currentTime + delay);
        osc.frequency.exponentialRampToValueAtTime(40, ctx.currentTime + delay + 0.1);
        gain.gain.setValueAtTime(1, ctx.currentTime + delay);
        gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + delay + 0.1);
        osc.start(ctx.currentTime + delay);
        osc.stop(ctx.currentTime + delay + 0.1);
      };
      playKnock(0);
      playKnock(0.15);
      playKnock(0.3);
    } catch(e) {}
  }
};

export function useMovement() {
  const { setMyPosition } = useGameStore();

  useEffect(() => {
    const activeKeys = new Set();
    let rAF;
    let lastTime = performance.now();

    const checkWalls = (nx, ny) => {
      for (const wall of WALLS) {
        if (isColliding(nx + OFFSET, ny + OFFSET, PLAYER_SIZE, PLAYER_SIZE, wall)) return true;
      }
      return false;
    };

    const checkDoors = (nx, ny) => {
      for (const key in DOORS) {
        const door = DOORS[key];
        if (isColliding(nx + OFFSET, ny + OFFSET, PLAYER_SIZE, PLAYER_SIZE, door)) return door;
      }
      return null;
    };

    const loop = (time) => {
      const dt = Math.min((time - lastTime) / 1000, 0.1); // caps dt at max 100ms
      lastTime = time;

      const { myPosition, currentUser } = useGameStore.getState();

      if (activeKeys.size > 0 && currentUser) {
        let dx = 0;
        let dy = 0;

        activeKeys.forEach(key => {
          if (MOVES[key]) {
            dx += MOVES[key].dx;
            dy += MOVES[key].dy;
          }
        });

        if (dx !== 0 && dy !== 0) {
           const length = Math.sqrt(dx * dx + dy * dy);
           dx /= length;
           dy /= length;
        }

        let newX = myPosition.x + dx * TILE_SPEED * dt;
        let newY = myPosition.y;

        let hitDoorX = checkDoors(newX, newY);
        if (checkWalls(newX, newY)) newX = myPosition.x;

        newY = myPosition.y + dy * TILE_SPEED * dt;
        let hitDoorY = checkDoors(newX, newY);
        if (checkWalls(newX, newY)) newY = myPosition.y;

        const hitDoor = hitDoorX || hitDoorY;

        let dir = myPosition.direction;
        if (dx > 0) dir = 'right';
        else if (dx < 0) dir = 'left';

        // Limit map boundaries just in case
        if (newX < 0) newX = 0;
        if (newX >= MAP_WIDTH_TILES) newX = MAP_WIDTH_TILES - 1;
        if (newY < 0) newY = 0;
        if (newY >= MAP_HEIGHT_TILES) newY = MAP_HEIGHT_TILES - 1;

        if (hitDoor && hitDoor.ownerId !== currentUser.id) {
           // It's not our door!
           triggerKnock(hitDoor);
           // Block movement into it
           newX = myPosition.x;
           newY = myPosition.y;
        }

        if (newX !== myPosition.x || newY !== myPosition.y || dir !== myPosition.direction) {
          setMyPosition(newX, newY, dir);
        }
      }

      rAF = requestAnimationFrame(loop);
    };

    const handleKeyDown = (e) => {
      if (MOVES[e.code]) activeKeys.add(e.code);
    };

    const handleKeyUp = (e) => {
      if (activeKeys.has(e.code)) activeKeys.delete(e.code);
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    rAF = requestAnimationFrame(loop);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      cancelAnimationFrame(rAF);
    };
  }, [setMyPosition]);
}

// lib/pushNotifications.js

// Using VAPID public key
const PUBLIC_VAPID_KEY = import.meta.env.VITE_VAPID_PUBLIC_KEY || 'mock-vapid-key';

function urlBase64ToUint8Array(base64String) {
  const padding = '='.repeat((4 - base64String.length % 4) % 4);
  const base64 = (base64String + padding)
    .replace(/\-/g, '+')
    .replace(/_/g, '/');

  const rawData = window.atob(base64);
  const outputArray = new Uint8Array(rawData.length);

  for (let i = 0; i < rawData.length; ++i) {
    outputArray[i] = rawData.charCodeAt(i);
  }
  return outputArray;
}

export async function subscribeUserToPush() {
  if ('serviceWorker' in navigator && 'PushManager' in window) {
    try {
      const registration = await navigator.serviceWorker.register('/sw.js');
      console.log('Service Worker registered');

      const subscription = await registration.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(PUBLIC_VAPID_KEY)
      });

      console.log('User is subscribed:', subscription);
      // Here we would send the subscription to Supabase
      return subscription;
    } catch (err) {
      console.error('Failed to subscribe to push notifications', err);
    }
  } else {
    console.warn('Push notifications are not supported by this browser.');
  }
}

export async function askNotificationPermission() {
  return new Promise((resolve, reject) => {
    const permissionResult = Notification.requestPermission(function(result) {
      resolve(result);
    });
    if (permissionResult) {
      permissionResult.then(resolve, reject);
    }
  }).then((permissionResult) => {
    if (permissionResult !== 'granted') {
      throw new Error("We weren't granted permission.");
    }
    return subscribeUserToPush();
  });
}

import { create } from 'zustand';
import { supabase } from '../lib/supabase';

export const useTaskStore = create((set, get) => ({
  tasks: [],
  isDashboardOpen: false,
  isPinned: false,

  toggleDashboard: () => set((state) => ({ isDashboardOpen: !state.isDashboardOpen })),
  setDashboardOpen: (isOpen) => set({ isDashboardOpen: isOpen }),
  togglePin: () => set((state) => {
    const newPinned = !state.isPinned;
    localStorage.setItem('guild-task-pinned', newPinned);
    return { isPinned: newPinned };
  }),

  // Database fetch & sync
  fetchTasks: async () => {
    const { data, error } = await supabase.from('tasks').select('*').order('created_at', { ascending: false });
    if (!error && data) {
      set({ tasks: data });
    }
  },

  subscribeToTasks: () => {
    get().fetchTasks();

    // Listen for any changes on the 'tasks' table
    supabase.channel('public:tasks')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'tasks' }, (payload) => {
         const newTask = payload.new;
         const currentUser = useGameStore.getState().currentUser;
         if (newTask.assigned_to === currentUser?.id) {
           window.dispatchEvent(new CustomEvent('in-game-notification', { detail: { message: `✅ NEW TASK ASSIGNED: ${newTask.title}` } }));
         }
         get().fetchTasks();
      })
      .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'tasks' }, (payload) => {
         const updatedTask = payload.new;
         const currentUser = useGameStore.getState().currentUser;
         if (updatedTask.assigned_to === currentUser?.id) {
           window.dispatchEvent(new CustomEvent('in-game-notification', { detail: { message: `🔄 TASK UPDATE: '${updatedTask.title}' moved to ${updatedTask.status.replace('_', ' ').toUpperCase()}` } }));
         }
         get().fetchTasks();
      })
      .subscribe();
  },

  updateTaskStatus: async (id, newStatus) => {
    // Optimistic UI update
    set((state) => ({
      tasks: state.tasks.map(t => t.id === id ? { ...t, status: newStatus } : t)
    }));
    // Supabase backend update
    await supabase.from('tasks').update({ status: newStatus }).eq('id', id);
  },

  addTask: async (newTask) => {
    await supabase.from('tasks').insert([{
      title: newTask.title,
      assigned_to: newTask.assigned_to,
      priority: newTask.priority,
      status: 'backlog',
      project_tag: newTask.project_tag || 'General',
      due_date: newTask.due_date || null
    }]);
  },

  // Hydrate pinned state on load
  initStore: () => {
    const pinned = localStorage.getItem('guild-task-pinned') === 'true';
    if (pinned) {
      set({ isPinned: true, isDashboardOpen: true });
    }
  }
}));
